 91	typedef enum pdu_session_satus_e {
 92	  PDU_SESSION_STATUS_NEW,
 93	  PDU_SESSION_STATUS_DONE,
 94	  PDU_SESSION_STATUS_ESTABLISHED,
 95	  PDU_SESSION_STATUS_REESTABLISHED, // after HO
 96	  PDU_SESSION_STATUS_TOMODIFY, // ENDC NSA
 97	  PDU_SESSION_STATUS_FAILED,
 98	  PDU_SESSION_STATUS_TORELEASE, // to release DRB between eNB and UE
 99	  PDU_SESSION_STATUS_RELEASED
100	} pdu_session_status_t;
101	
102	typedef struct pdusession_s {
103	  /* Unique pdusession_id for the UE. */
104	  int pdusession_id;
105	  byte_array_t nas_pdu;
106	  uint8_t nb_qos;
107	  /* Quality of service for this pdusession */
108	  pdusession_level_qos_parameter_t qos[QOSFLOW_MAX_VALUE];
109	  /* The transport layer address for the IP packets */
110	  pdu_session_type_t pdu_session_type;
111	  // NG-RAN endpoint of the NG-U (N3) transport bearer
112	  gtpu_tunnel_t n3_outgoing;
113	  // UPF endpoint of the NG-U (N3) transport bearer
114	  gtpu_tunnel_t n3_incoming;
115	  nssai_t nssai;
116	} pdusession_t;
