125	typedef struct drb_s {
126	  int status;
127	  int drb_id;
128	  struct cnAssociation_s {
129	    int present;
130	    int eps_BearerIdentity;
131	    struct sdap_config_s {
132	      bool defaultDRB;
133	      int pdusession_id;
134	      int sdap_HeaderDL;
135	      int sdap_HeaderUL;
136	      int mappedQoS_FlowsToAdd[QOSFLOW_MAX_VALUE];
137	    } sdap_config;
138	  } cnAssociation;
139	  struct pdcp_config_s {
140	    int discardTimer;
141	    int pdcp_SN_SizeUL;
142	    int pdcp_SN_SizeDL;
143	    int t_Reordering;
144	    int integrityProtection;
145	    struct headerCompression_s {
146	      int NotUsed;
147	      int present;
148	    } headerCompression;
149	    struct ext1_s {
150	      int cipheringDisabled;
151	    } ext1;
152	  } pdcp_config;
153	  // F1-U Downlink Tunnel Config (on DU side)
154	  gtpu_tunnel_t du_tunnel_config;
155	  // F1-U Uplink Tunnel Config (on CU-UP side)
156	  gtpu_tunnel_t cuup_tunnel_config;
157	} drb_t;
