160	  RRC_ACTION_NONE, /* no transaction ongoing */
161	  RRC_SETUP,
162	  RRC_SETUP_FOR_REESTABLISHMENT,
163	  RRC_REESTABLISH,
164	  RRC_REESTABLISH_COMPLETE,
165	  RRC_DEDICATED_RECONF,
166	  RRC_PDUSESSION_ESTABLISH,
167	  RRC_PDUSESSION_MODIFY,
168	  RRC_PDUSESSION_RELEASE,
169	  RRC_UECAPABILITY_ENQUIRY,
170	} rrc_action_t;
